#!/usr/bin/env node

/**
 * Seed 100 knowledge memories into the HiveMind Global Hive.
 *
 * Usage:
 *   HIVEMIND_URL=https://hivemind.onrender.com \
 *   HIVE_INTERNAL_KEY=xxx \
 *   node scripts/seed-knowledge.js
 */

const HIVEMIND_URL = process.env.HIVEMIND_URL || 'http://localhost:3002';
const HIVE_INTERNAL_KEY = process.env.HIVE_INTERNAL_KEY;

if (!HIVE_INTERNAL_KEY) {
  console.error('ERROR: HIVE_INTERNAL_KEY environment variable is required');
  process.exit(1);
}

