// ─── Seed Logic ─────────────────────────────────────────────────────

async function seed() {
  console.log(`\nSeeding ${memories.length} knowledge memories to ${HIVEMIND_URL}\n`);

  const BATCH_SIZE = 10;
  let totalSeeded = 0;

  for (let i = 0; i < memories.length; i += BATCH_SIZE) {
    const batch = memories.slice(i, i + BATCH_SIZE);
    const batchNum = Math.floor(i / BATCH_SIZE) + 1;
    const totalBatches = Math.ceil(memories.length / BATCH_SIZE);

    console.log(`  Batch ${batchNum}/${totalBatches}: seeding ${batch.length} memories...`);

    try {
      const response = await fetch(`${HIVEMIND_URL}/v1/global_hive/seed`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-hive-internal': HIVE_INTERNAL_KEY,
        },
        body: JSON.stringify({ memories: batch }),
      });

      const data = await response.json();

      if (response.ok && data.success) {
        totalSeeded += data.data.seeded;
        console.log(`    ✓ Seeded ${data.data.seeded} memories`);
      } else {
        console.error(`    ✗ Batch ${batchNum} failed:`, data.error || response.statusText);
      }
    } catch (err) {
      console.error(`    ✗ Batch ${batchNum} error:`, err.message);
    }
  }

  console.log(`\nDone! Total seeded: ${totalSeeded}/${memories.length}\n`);

  // Print category summary
  const categories = {};
  for (const mem of memories) {
    if (!categories[mem.category]) categories[mem.category] = { count: 0, free: 0, paid: 0 };
    categories[mem.category].count++;
    if (mem.price_usdc === 0) categories[mem.category].free++;
    else categories[mem.category].paid++;
  }
  console.log('Category Summary:');
  for (const [cat, stats] of Object.entries(categories)) {
    console.log(`  ${cat}: ${stats.count} total (${stats.free} free, ${stats.paid} paid)`);
  }
}

seed().catch(err => {
  console.error('Fatal error:', err);
  process.exit(1);
});
